using UnityEngine;

/// <summary>
/// Zona de queda NÃO-letal (Tarefa "Morte e checkpoints"): ao entrar nesta
/// zona (ex: poço/abismo sem dano grave), o player é reposicionado no
/// checkpoint actual (<see cref="PlayerDeathHandler.TeleportToCheckpoint"/> —
/// checkpoint temporário da área, ou último Refúgio Seguro), SEM disparar a
/// sequência de morte (sem animação/SFX de morte, sem RegisterDeath, sem reset
/// de inimigos).
///
/// Opcionalmente pode aplicar um pequeno dano (<see cref="damage"/>, em
/// corações) ao cair — ex: "queda magoa mas não mata". Se esse dano esvaziar
/// os corações, a sequência de morte normal (PlayerDeathHandler) assume o
/// controlo e este componente não reposiciona (evita duplo reposicionamento).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class FallResetZone : MonoBehaviour
{
    [Header("Dano (opcional)")]
    [Tooltip("Corações de dano ao cair nesta zona. 0 = sem dano, apenas reposiciona no checkpoint.")]
    [Min(0)] public int damage = 0;

    [Header("Feedback")]
    [Tooltip("Som tocado ao reposicionar o player (não tocado se o dano causar morte normal).")]
    public AudioClip fallSfx;

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        var progress = PlayerProgress.Instance;

        if (damage > 0 && progress != null)
        {
            progress.Damage(damage);

            // Dano esvaziou os corações: a sequência de morte normal
            // (PlayerDeathHandler.OnHeartsDepleted → Respawn) já trata do
            // reposicionamento/reset — não duplicar aqui.
            if (progress.currentHearts <= 0) return;
        }

        var deathHandler = other.GetComponent<PlayerDeathHandler>();
        if (deathHandler == null) return;

        deathHandler.TeleportToCheckpoint();

        if (fallSfx != null) AudioManager.Instance?.PlaySE(fallSfx);
    }
}
